+			func(appAddr string, height int64, relayChain, geoZone string) (*coreTypes.Session, error) {
+				return session, nil
+			}).
+		MaxTimes(1)
+	utilityMock.EXPECT().GetModuleName().Return(modules.UtilityModuleName).AnyTimes()
+
+	return utilityMock
+}

